import "fmt"

func solve(landStartTime []int64, landDuration []int64, waterStartTime []int64, waterDuration []int64) int64 {
    // Calculate all possible end times for land attractions
    landEndTimes := make([]int64, len(landStartTime))
    for i := 0; i < len(landStartTime); i++ {
        landEndTimes[i] = landStartTime[i] + landDuration[i]
    }

    // Calculate all possible end times for water attractions
    waterEndTimes := make([]int64, len(waterStartTime))
    for j := 0; j < len(waterStartTime); j++ {
        waterEndTimes[j] = waterStartTime[j] + waterDuration[j]
    }

    // Try all combinations of one land and one water attraction
    var minTime int64 = 1<<63 - 1
    for _, landEnd := range landEndTimes {
        for _, waterEnd := range waterEndTimes {
            totalTime := max(landEnd, waterEnd)
            if totalTime < minTime {
                minTime = totalTime
            }
        }
    }

    return minTime
}

func max(a, b int64) int64 {
    if a > b {
        return a
    }
    return b
}
